using namespace std;

enum class AccountType {
    SAVINGS,
    CHECKING,
    JOINT
};

class Account {
public:
    Account(AccountType type, double balance) : type(type), balance(balance) {
        if (balance < 0) throw invalid_argument("Balance cannot be negative");
    }

    virtual double calculateInterest() const = 0;

    AccountType getType() const { return type; }
    double getBalance() const { return balance; }

    void deposit(double amount) {
        if (amount < 0) throw invalid_argument("Deposit amount cannot be negative");
        balance += amount;
    }

    void withdraw(double amount) {
        if (amount < 0) throw invalid_argument("Withdrawal amount cannot be negative");
        if (amount > balance) throw invalid_argument("Insufficient funds");
        balance -= amount;
    }

    void logAction(const string &action, double amount) {
        cout << "Action: " << action << ", Amount: " << amount << endl;
    }

private:
    AccountType type;
    double balance;
};

class SavingsAccount : public Account {
public:
    SavingsAccount(AccountType type, double balance) : Account(type, balance) {
        // No additional logic needed
    }

    double calculateInterest() const override {
        return 0.02 * balance; // 2% interest rate
    }
};

class CheckingAccount : public Account {
public:
    CheckingAccount(AccountType type, double balance) : Account(type, balance) {
        // No additional logic needed
    }

    double calculateInterest() const override {
        return 0.01 * balance; // 1% interest rate
    }
};

class JointAccount : public Account {
public:
    JointAccount(AccountType type, double balance) : Account(type, balance) {
        // No additional logic needed
    }

    double calculateInterest() const override {
        return 0.015 * balance; // 1.5% interest rate
    }
};

int main() {
    stack<Account*> accountsStack;

    // Create accounts
    accountsStack.push(new SavingsAccount(AccountType::SAVINGS, 1000.0));
    accountsStack.push(new CheckingAccount(AccountType::CHECKING, 500.0));
    accountsStack.push(new JointAccount(AccountType::JOINT, 2000.0));

    // Perform actions
    for (auto it = accountsStack.begin(); it != accountsStack.end(); ++it) {
        Account* account = *it;
        account->deposit(500.0);
        account->withdraw(300.0);
        account->logAction("Deposit", 500.0);
        account->logAction("Withdrawal", 300.0);
    }

    // Clean up
    for (auto it = accountsStack.begin(); it != accountsStack.end(); ++it) {
        delete *it;
    }

    return 0;
}

