def fibonacci(n, memo={}):
    if n <= 0:
        raise ValueError("Input must be a positive integer.")
    if n == 1:
        return 0
    if n in memo:
        return memo[n]
    memo[n] = fibonacci(n-1, memo) + fibonacci(n-2, memo)
    return memo[n]

