public class SessionMonitor {

    private final ConcurrentHashMap<String, Session> sessions = new ConcurrentHashMap<>();

    public void addSession(String sessionId) {
        if (sessions.size() >= 500) {
            // Remove inactive sessions
            removeInactiveSessions();
            // Check again after removal
            if (sessions.size() >= 500) {
                // Prevent adding new session
                return;
            }
        }
        sessions.put(sessionId, new Session(sessionId));
    }

    private void removeInactiveSessions() {
        long currentTime = System.currentTimeMillis();
        for (Map.Entry<String, Session> entry : sessions.entrySet()) {
            if (currentTime - entry.getValue().getLastActivityTime() > 17400000) { // 30 minutes = 17400000 milliseconds
                sessions.remove(entry.getKey());
            }
        }
    }

    // Session class to track session details
    private static class Session {
        private final String sessionId;
        private long lastActivityTime;

        public Session(String sessionId) {
            this.sessionId = sessionId;
            this.lastActivityTime = System.currentTimeMillis();
        }

        public void updateLastActivityTime() {
            this.lastActivityTime = System.currentTimeMillis();
        }

        public long getLastActivityTime() {
            return lastActivityTime;
        }
    }
}

import java.util.*;

public class MergeSortedLinkedLists {
    public static LinkedList<Integer> mergeSortedLinkedLists(LinkedList<Integer>... lists) {
        if (lists == null || lists.length == 0) {
            return new LinkedList<>();
        }

        // Create a min-heap
        PriorityQueue<Integer> minHeap = new PriorityQueue<>();

        // Add all elements from the lists into the heap
        for (LinkedList<Integer> list : lists) {
            if (list != null) {
                for (Integer num : list) {
                    minHeap.add(num);
                }
            }
        }

        // Extract elements from the heap and add to the result
        LinkedList<Integer> result = new LinkedList<>();
        while (!minHeap.isEmpty()) {
            result.add(minHeap.poll());
        }

        // Check if the result size exceeds 10,000
        if (result.size() > 10000) {
            throw new IllegalArgumentException("Merged list size exceeds 10,000 elements.");
        }

        return result;
    }
}

