use std::collections::HashSet;

fn max_non_adjacent_sum(arr: &[i32]) -> i32 {
    if arr.is_empty() {
        return 0;
    }

    let mut dp = vec![0; arr.len()];
    let mut hash_set = HashSet::new();

    dp[0] = arr[0];
    hash_set.insert(dp[0]);

    for i in 1..arr.len() {
        let mut max_sum = arr[i];
        for j in 0..i {
            if dp[j] + arr[i] > max_sum {
                max_sum = dp[j] + arr[i];
            }
        }
        dp[i] = max_sum;
        hash_set.insert(dp[i]);
    }

    dp[arr.len() - 1]
}

fn main() {
    let arr = [2, 5, 1, 10, 15, 20];
    let result = max_non_adjacent_sum(&arr);
    println!("Maximum sum: {}", result);
}
