public class WordFrequency {

    public static Map<String, Integer> getWordFrequency(String input) {
        // Normalize the input: lowercase and remove punctuation
        String normalized = input.toLowerCase().replaceAll("[^a-z]", " ");

        // Split into words
        String[] words = normalized.split("\\s+");

        // Use a HashMap to store word frequencies
        Map<String, Integer> frequencyMap = new HashMap<>();

        // Limit the number of entries to 10,000
        if (frequencyMap.size() >= 10000) {
            return null;
        }

        // Count frequencies
        for (String word : words) {
            if (word.isEmpty()) continue;
            frequencyMap.put(word, frequencyMap.getOrDefault(word, 0) + 1);
        }

        return frequencyMap;
    }
}

