    bool flightExists(const std::string& airline, const std::string& flightNumber) {
        auto it = airlines.find(airline);
        if (it == airlines.end()) return false;
        auto flightIt = std::find(it->second.begin(), it->second.end(), flightNumber);
        return flightIt != it->second.end();
    }

    // Helper function to check if a booking exists
    bool bookingExists(const std::string& bookingId) {
        return bookings.find(bookingId) != bookings.end();
    }

    // Helper function to add a flight
    void addFlight(const std::string& airline, const std::string& flightNumber) {
        if (flightExists(airline, flightNumber)) {
            throw std::runtime_error("Flight already exists");
        }
        if (airlines[airline].size() >= 300) {
            throw std::runtime_error("Maximum number of flights per airline reached");
        }
        airlines[airline].push_back(flightNumber);
    }

    // Helper function to remove a flight
    void removeFlight(const std::string& airline, const std::string& flightNumber) {
        auto it = airlines.find(airline);
        if (it == airlines.end()) return;
        auto flightIt = std::find(it->second.begin(), it->second.end(), flightNumber);
        if (flightIt == it->second.end()) return;
        it->second.erase(flightIt);
    }

