using namespace std;

const int INF = INT_MAX;

// Define the grid dimensions
const int MAX_ROWS = 1000;
const int MAX_COLS = 1000;

// Define the direction vectors for movement
int dx[] = {0, 1, -1, 0};
int dy[] = {1, 0, 0, -1};

// Function to find the shortest path using Dijkstra's algorithm
int shortestPath(int grid[MAX_ROWS][MAX_COLS], int rows, int cols) {
    // Initialize distance matrix with INF
    vector<vector<int>> dist(rows, vector<int>(cols, INF));
    // Priority queue for Dijkstra's algorithm
    priority_queue<pair<int, pair<int, int>>, vector<pair<int, pair<int, int>>, greater<pair<int, pair<int, int>>>> pq;

    // Start from the top-left corner
    dist[0][0] = 0;
    pq.push({0, {0, 0}});

    // Directions: right, down, left, up
    while (!pq.empty()) {
        int distCurrent = pq.top().first;
        int x = pq.top().second.first;
        int y = pq.top().second.second;
        pq.pop();

        // Check if we reached the destination
        if (x == rows - 1 && y == cols - 1) {
            return distCurrent;
        }

        // Explore neighbors
        for (int i = 0; i < 4; ++i) {
            int nx = x + dx[i];
            int ny = y + dy[i];

            // Check if the new position is within bounds and not visited
            if (nx >= 0 && nx < rows && ny >= 0 && ny < cols && dist[nx][ny] > distCurrent + 1) {
                dist[nx][ny] = distCurrent + 1;
                pq.push({dist[nx][ny], {nx, ny}});
            }
        }
    }

    return -1; // No path found
}

int main() {
    int rows, cols;
    cout << "Enter number of rows and columns: ";
    cin >> rows >> cols;

    int grid[MAX_ROWS][MAX_COLS];
    cout << "Enter grid values (0 for empty, 1 for occupied): ";
    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < cols; ++j) {
            cin >> grid[i][j];
        }
    }

    int result = shortestPath(grid, rows, cols);
    if (result != -1) {
        cout << "Shortest path found: " << result << endl;
    } else {
        cout << "No path found." << endl;
    }

    return 0;
}

