type Buffer struct {
	Data []TemperatureData
	mu   sync.Mutex
}

func (b *Buffer) Add(data TemperatureData) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.Data = append(b.Data, data)
}

func (b *Buffer) Get() []TemperatureData {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.Data
}

func (b *Buffer) Clear() {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.Data = []TemperatureData{}
}

func (b *Buffer) IsEmpty() bool {
	return len(b.Data) == 0
}

func (b *Buffer) Size() int {
	return len(b.Data)
}

func main() {
	// Example sensor data
	sensorData := SensorData{
		SensorID: "Sensor1",
		Data: []TemperatureData{
			{Value: 22.5},
			{Value: 23.0},
			{Value: 22.8},
			{Value: 23.2},
			{Value: 22.9},
		},
	}

	// Buffer to store temperature data
	buffer := &Buffer{}

	// Process sensor data
	for _, data := range sensorData.Data {
		buffer.Add(data)
	}

	// Check if buffer is empty
	if buffer.IsEmpty() {
		log.Printf("Buffer is empty. No data to process.\n")
		return
	}

	// Get data from buffer
	data := buffer.Get()

	// Check if buffer size exceeds 1000
	if buffer.Size() > 1000 {
		log.Printf("Buffer overflow: %d entries exceed 1000.\n", buffer.Size())
		buffer.Clear()
		return
	}

	// Compute moving average
	movingAverage := 0.0
	if len(data) > 0 {
		movingAverage = float64(sum(data)) / float64(len(data))
	}

	// Log the result
	log.Printf("Moving average: %.2f\n", movingAverage)
}

func sum(data []TemperatureData) float64 {
	total := 0.0
	for _, d := range data {
		total += d.Value
	}
	return total
