type fibMap struct {
	m map[int]int
}

func (m *fibMap) Get(n int) int {
	if val, exists := m.m[n]; exists {
		return val
	}
	return 0
}

func (m *fibMap) Put(n int, val int) {
	m.m[n] = val
}

func (m *fibMap) Update(n int, f func(int) int) {
	if val, exists := m.m[n]; exists {
		m.m[n] = f(val)
	} else {
		m.m[n] = f(0)
	}
}

func main() {
	var fibMap fibMap
	var mu sync.Mutex

	// Initialize the map with base cases
	fibMap.m = make(map[int]int)
	fibMap.m[0] = 0
	fibMap.m[1] = 1

	// Function to compute Fibonacci number
	fib := func(n int) int {
		mu.Lock()
		defer mu.Unlock()
		if val, exists := fibMap.Get(n); exists {
			return val
		}
		if n == 0 {
			fibMap.Put(n, 0)
			return 0
		}
		if n == 1 {
			fibMap.Put(n, 1)
			return 1
		}
		result := fib(n-1) + fib(n-2)
		fibMap.Put(n, result)
		return result
	}

	// Compute first 1000 Fibonacci numbers
	for i := 0; i < 1000; i++ {
		fib(i)
	}

	// Print results
	for i := 0; i < 10; i++ {
		fmt.Printf("Fib(%d) = %d\n", i, fib(i))
	}
}

