    for (const auto& arr : arrays) {
        for (int num : arr) {
            pq.push(num);
        }
    }

    while (!pq.empty()) {
        result.push_back(pq.top());
        pq.pop();
    }

    return result;
}

import java.util.PriorityQueue;
import java.util.Queue;
import java.util.concurrent.TimeUnit;

public class TaskProcessor {
    public static void processTasks(Queue<Task> taskQueue) throws IllegalArgumentException {
        if (taskQueue == null || taskQueue.isEmpty()) {
            throw new IllegalArgumentException("Queue is empty");
        }

        PriorityQueue<Task> priorityQueue = new PriorityQueue<>(100);
        long totalExecutionTime = 0;

        while (!taskQueue.isEmpty()) {
            Task task = taskQueue.poll();
            if (task == null) {
                throw new IllegalArgumentException("Task cannot be null");
            }
            priorityQueue.offer(task);
        }

        while (!priorityQueue.isEmpty()) {
            Task task = priorityQueue.poll();
            totalExecutionTime += task.getDuration();
        }

        System.out.println("Total execution time: " + totalExecutionTime + " milliseconds");
    }

    public static void main(String[] args) {
        // Example usage
        Queue<Task> taskQueue = new java.util.LinkedList<>();
        taskQueue.add(new Task(1, 1000));
        taskQueue.add(new Task(2, 2000));
        taskQueue.add(new Task(3, 3000));

        try {
            processTasks(taskQueue);
        } catch (IllegalArgumentException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}

class Task {
    private final int priority;
    private final long duration;

    public Task(int priority, long duration) {
        this.priority = priority;
        this.duration = duration;
    }

    public int getPriority() {
        return priority;
    }

    public long getDuration() {
        return duration;
    }
}

