func maxSubarraySum(arr []int) int {
	if len(arr) == 0 {
		return 0
	}

	maxCurrent, maxGlobal := arr[0], arr[0]

	for i := 1; i < len(arr); i++ {
		maxCurrent = max(arr[i], maxCurrent+arr[i])
		maxGlobal = max(maxGlobal, maxCurrent)
	}

	return maxGlobal
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

