using namespace std;

class Product {
public:
    string name;
    double price;
    int quantity;
    string genre;

    Product(string n, double p, int q, string g) : name(n), price(p), quantity(q), genre(g) {}
};

class Bookstore {
private:
    map<string, Product> catalog;
    int maxEntries = 500;

public:
    Bookstore() {}

    void addProduct(const string& name, double price, int quantity, const string& genre) {
        if (catalog.size() >= maxEntries) {
            cout << "Error: Catalog is full." << endl;
            return;
        }
        catalog[name] = Product(name, price, quantity, genre);
    }

    void displayCatalog() {
        for (const auto& entry : catalog) {
            cout << "Name: " << entry.first << ", Price: $" << entry.second.price << ", Quantity: " << entry.second.quantity << ", Genre: " << entry.second.genre << endl;
        }
    }

    void applyDiscounts(vector<string> items) {
        for (const auto& item : items) {
            if (catalog.find(item) != catalog.end()) {
                double discount = 0.0;
                if (catalog[item].price >= 100) discount = 0.10;
                if (catalog[item].price >= 200) discount = 0.20;
                if (catalog[item].price >= 300) discount = 0.30;

                double discountedPrice = catalog[item].price * (1 - discount);
                catalog[item].price = discountedPrice;
            }
        }
    }

    void sortCatalog(string sortBy) {
        if (sortBy == "price") {
            vector<pair<string, Product>> items;
            for (const auto& entry : catalog) {
                items.push_back({ entry.first, entry.second });
            }
            sort(items.begin(), items.end(), [](const pair<string, Product>& a, const pair<string, Product>& b) {
                return a.second.price < b.second.price;
            });
            for (const auto& item : items) {
                catalog[item.first] = item.second;
            }
        } else if (sortBy == "genre") {
            vector<pair<string, Product>> items;
            for (const auto& entry : catalog) {
                items.push_back({ entry.first, entry.second });
            }
            sort(items.begin(), items.end(), [](const pair<string, Product>& a, const pair<string, Product>& b) {
                return a.second.genre < b.second.genre;
            });
            for (const auto& item : items) {
                catalog[item.first] = item.second;
            }
        }
    }
};

int main() {
    Bookstore bookstore;

    // Add products
    bookstore.addProduct("Book1", 29.99, 100, "Fiction");
    bookstore.addProduct("Book2", 49.99, 50, "Non-Fiction");
    bookstore.addProduct("Book3", 19.99, 200, "Fiction");
    bookstore.addProduct("Book4", 39.99, 75, "Science");
    bookstore.addProduct("Book5", 59.99, 150, "Fiction");

    // Display catalog
    cout << "Catalog:" << endl;
    bookstore.displayCatalog();

    // Apply discounts
    vector<string> items = {"Book1", "Book3"};
    bookstore.applyDiscounts(items);

    // Sort by price
    bookstore.sortCatalog("price");

    // Display updated catalog
    cout << "\nUpdated Catalog:" << endl;
    bookstore.displayCatalog();

    return 0;
}

