using namespace std;

class MergeArrays {
private:
    vector<vector<int>> arrays;
    priority_queue<pair<int, int>> heap;
    int arrayIndex = 0;

public:
    MergeArrays(const string& inputFile = "input.txt") {
        ifstream file(inputFile);
        string line;
        while (getline(file, line)) {
            istringstream iss(line);
            int num;
            while (iss >> num) {
                arrays.push_back(vector<int>());
                arrays.back().push_back(num);
            }
        }
    }

    void mergeArrays() {
        for (int i = 0; i < arrays.size(); ++i) {
            if (!arrays[i].empty()) {
                heap.push({arrays[i][0], i});
            }
        }

        vector<int> result;
        while (!heap.empty()) {
            pair<int, int> top = heap.top();
            result.push_back(top.first);
            heap.pop();

            int arrayIndex = top.second;
            if (arrayIndex < arrays.size() - 1 && !arrays[arrayIndex + 1].empty()) {
                heap.push({arrays[arrayIndex + 1][0], arrayIndex + 1});
            }
        }

        // Output to console
        cout << "Merged array: ";
        for (int num : result) {
            cout << num << " ";
        }
        cout << endl;
    }
};

int main(int argc, char* argv[]) {
    if (argc < 2) {
        cerr << "Usage: " << argv[0] << " <inputFile>" << endl;
        return 1;
    }

    MergeArrays merger(argv[1]);
    merger.mergeArrays();

    return 0;
}

