class Employee {
public:
    std::string name;
    int age;
    Employee(const std::string& name, int age) : name(name), age(age) {}
    bool operator<(const Employee& other) const {
        if (age != other.age) return age < other.age;
        return name < other.name;
    }
    bool operator<=(const Employee& other) const {
        return *this < other || *this == other;
    }
    bool operator>(const Employee& other) const {
        return !(*this <= other);
    }
    bool operator>=(const Employee& other) const {
        return *this > other || *this == other;
    }
    bool operator!=(const Employee& other) const {
        return !(*this == other);
    }
    bool operator==(const Employee& other) const {
        return name == other.name && age == other.age;
    }
};

class EmployeeDeque {
public:
    EmployeeDeque(size_t capacity) : capacity_(capacity), deque_() {
        if (capacity_ < 0) {
            throw std::invalid_argument("Capacity must be non-negative.");
        }
    }

    void add(const Employee& emp) {
        if (deque_.size() >= capacity_) {
            throw std::overflow_error("Deque is full.");
        }
        deque_.push_back(emp);
    }

    void sort() {
        std::sort(deque_.begin(), deque_.end());
    }

    void print() const {
        for (const auto& emp : deque_) {
            std::cout << emp.name << " " << emp.age << std::endl;
        }
    }

private:
    size_t capacity_;
    std::deque<Employee> deque_;
};

int main() {
    try {
        EmployeeDeque empDeque(800);
        empDeque.add(Employee("Alice", 30));
        empDeque.add(Employee("Bob", 25));
        empDeque.add(Employee("Charlie", 35));
        empDeque.add(Employee("David", 40));
        empDeque.sort();
        empDeque.print();
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}

