use std::fs::File;
use std::io::{BufReader, BufRead};
use std::collections::{HashMap, VecDeque};

fn main() {
    let filename = "input.txt";
    let mut word_counts = HashMap::new();
    let mut word_queue = VecDeque::new();

    // Read file and process each line
    let file = File::open(filename).expect("File not found");
    let reader = BufReader::new(file);

    for line in reader.lines() {
        let line_str = line.expect("Failed to read line");
        let cleaned_line = line_str
            .to_lowercase()
            .chars()
            .filter(|c| c.is_alphanumeric())
            .collect::<String>();
        let words: Vec<&str> = cleaned_line.split_whitespace().collect();

        for word in words {
            // Remove punctuation
            let cleaned_word = word
                .chars()
                .filter(|c| c.is_alphanumeric())
                .collect::<String>();
            if !cleaned_word.is_empty() {
                word_queue.push_back(cleaned_word);
            }
        }
    }

    // Count words
    for word in word_queue {
        *word_counts.entry(word).or_insert(0) += 1;
    }

    // Limit to 10,000 elements
    if word_counts.len() > 10_000 {
        let mut new_counts = HashMap::new();
        for (k, v) in word_counts.iter() {
            if new_counts.len() < 10_000 {
                new_counts.insert(k.clone(), v.clone());
            }
        }
        word_counts = new_counts;
    }

    // Display most frequent words
    let mut sorted_counts: Vec<(&String, usize)> = word_counts.into_iter().collect();
    sorted_counts.sort_by(|a, b| b.1.reverse().cmp(&a.1));
    sorted_counts.reverse();

    println!("Most frequent words (top 10,000):");
    for (word, count) in sorted_counts {
        println!("{}: {}", word, count);
    }
}
