use std::collections::LinkedList;
use std::fmt::{self, Debug};
use std::thread;
use std::time::Duration;

#[derive(Debug, PartialEq, Eq, Clone)]
pub struct Message {
    pub id: String,
    pub timestamp: String,
    pub content: String,
}

impl Message {
    pub fn new(id: &str, timestamp: &str, content: &str) -> Self {
        Message {
            id: id.to_string(),
            timestamp: timestamp.to_string(),
            content: content.to_string(),
        }
    }
}

#[derive(Debug)]
pub struct MessageQueue {
    queue: LinkedList<Message>,
    max_size: usize,
}

impl MessageQueue {
    pub fn new(max_size: usize) -> Self {
        MessageQueue {
            queue: LinkedList::new(),
            max_size,
        }
    }

    pub fn enqueue(&mut self, message: Message) -> Result<(), String> {
        if self.queue.len() >= self.max_size {
            return Err("Queue is full".to_string());
        }
        self.queue.push_back(message);
        Ok(())
    }

    pub fn dequeue(&mut self) -> Result<Message, String> {
        if self.queue.is_empty() {
            return Err("Queue is empty".to_string());
        }
        let message = self.queue.remove_front().unwrap();
        Ok(message)
    }

    pub fn lookup(&self, id: &str) -> Option<&Message> {
        self.queue.iter().find(|msg| msg.id == id)
    }

    pub fn is_empty(&self) -> bool {
        self.queue.is_empty()
    }

    pub fn is_full(&self) -> bool {
        self.queue.len() == self.max_size
    }
}

fn main() {
    let mut queue = MessageQueue::new(500);

    let msg1 = Message::new("1", "2023-04-01T12:00:00", "Hello");
    let msg2 = Message::new("2", "2023-04-01T12:00:01", "World");
    let msg3 = Message::new("3", "2023-04-01T12:00:02", "Rust");

    // Enqueue messages
    for msg in &[msg1, msg2, msg3] {
        if let Err(e) = queue.enqueue(*msg) {
            eprintln!("Enqueue failed: {}", e);
        }
    }

    // Dequeue messages
    let mut dequeue_result = None;
    for _ in 0..3 {
        dequeue_result = queue.dequeue();
        if let Ok(msg) = dequeue_result {
            println!("Dequeued: {}", msg.id);
        } else {
            eprintln!("Dequeue failed");
        }
    }

    // Lookup
    if let Some(msg) = queue.lookup("1") {
        println!("Found: {}", msg.id);
    } else {
        eprintln!("Message not found");
    }

    // Check limits
    println!("Queue is full: {}", queue.is_full());
    println!("Queue is empty: {}", queue.is_empty());
}
