const int MAX_SEATS = 10000;

class CinemaSeatSystem {
private:
    std::vector<std::string> seats;
    std::mutex mtx;

public:
    CinemaSeatSystem() {
        // Initialize with 10,000 seats
        for (int i = 0; i < MAX_SEATS; ++i) {
            seats.push_back("Available");
        }
    }

    void reserve(int seatNumber, std::string name) {
        std::lock_guard<std::mutex> lock(mtx);
        if (seatNumber < 1 || seatNumber > MAX_SEATS) {
            throw std::invalid_argument("Invalid seat number");
        }

        if (seats[seatNumber - 1] == "Available") {
            seats[seatNumber - 1] = name;
        } else {
            throw std::runtime_error("Seat already booked");
        }
    }

    void updateReservation(int seatNumber, std::string name) {
        std::lock_guard<std::mutex> lock(mtx);
        if (seatNumber < 1 || seatNumber > MAX_SEATS) {
            throw std::invalid_argument("Invalid seat number");
        }

        if (seats[seatNumber - 1] != "Available") {
            seats[seatNumber - 1] = name;
        }
    }

    void cancelReservation(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        if (seatNumber < 1 || seatNumber > MAX_SEATS) {
            throw std::invalid_argument("Invalid seat number");
        }

        if (seats[seatNumber - 1] != "Available") {
            seats[seatNumber - 1] = "Available";
        }
    }

    bool isSeatAvailable(int seatNumber) {
        std::lock_guard<std::mutex> lock(mtx);
        if (seatNumber < 1 || seatNumber > MAX_SEATS) {
            return false;
        }
        return seats[seatNumber - 1] == "Available";
    }
};

int main() {
    CinemaSeatSystem cinema;

    try {
        cinema.reserve(1, "Alice");
        cinema.reserve(2, "Bob");
        cinema.reserve(3, "Charlie");

        std::cout << "Seat 1: " << cinema.isSeatAvailable(1) << std::endl;
        std::cout << "Seat 2: " << cinema.isSeatAvailable(2) << std::endl;
        std::cout << "Seat 3: " << cinema.isSeatAvailable(3) << std::endl;

        cinema.updateReservation(1, "Alice");
        std::cout << "Seat 1: " << cinema.isSeatAvailable(1) << std::endl;

        cinema.cancelReservation(1);
        std::cout << "Seat 1: " << cinema.isSeatAvailable(1) << std::endl;

        cinema.cancelReservation(2);
        std::cout << "Seat 2: " << cinema.isSeatAvailable(2) << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}

import heapq

class TaskManager:
    def __init__(self):
        self.tasks = []
        self.task_id = 0

    def add_task(self, deadline, priority, description):
        """Add a task with a deadline and priority."""
        self.task_id += 1
        task = {
            'id': self.task_id,
            'deadline': deadline,
            'priority': priority,
            'description': description,
            'status': 'pending'
        }
        heapq.heappush(self.tasks, task)
        return self.task_id

    def update_task(self, task_id, deadline, priority, description):
        """Update an existing task."""
        for i in range(len(self.tasks)):
            task = self.tasks[i]
            if task['id'] == task_id:
                task['deadline'] = deadline
                task['priority'] = priority
                task['description'] = description
                heapq.heapify(self.tasks)
