public class TaskScheduler {
    private TreeSet<Task> tasks;
    private static final int MAX_TASKS = 200;
    private static final String LOG_FILE = "task_scheduler.log";

    public TaskScheduler() {
        tasks = new TreeSet<>();
    }

    public void addTask(Task task) {
        if (tasks.size() >= MAX_TASKS) {
            throw new IllegalStateException("Cannot add task: TreeSet is full");
        }
        tasks.add(task);
        logOperation("Added", task);
    }

    public void removeTask(Task task) {
        if (!tasks.contains(task)) {
            throw new IllegalArgumentException("Task not found");
        }
        tasks.remove(task);
        logOperation("Removed", task);
    }

    public Task fetchTask(int id) {
        for (Task task : tasks) {
            if (task.getId() == id) {
                return task;
            }
        }
        throw new NoSuchElementException("Task not found");
    }

    private void logOperation(String operation, Task task) {
        try (FileWriter writer = new FileWriter(LOG_FILE, true)) {
            writer.write(String.format("%s: %s - %s\n", new Date(), operation, task));
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    public static void main(String[] args) {
        TaskScheduler scheduler = new TaskScheduler();
        Task task1 = new Task(1, "Task 1", 5);
        Task task2 = new Task(2, "Task 2", 3);
        Task task3 = new Task(3, "Task 3", 4);

        try {
            scheduler.addTask(task1);
            scheduler.addTask(task2);
            scheduler.addTask(task3);
            System.out.println("Tasks added: " + scheduler.tasks.size());
            System.out.println("Task 1: " + scheduler.fetchTask(1));
            scheduler.removeTask(task1);
            System.out.println("Task 1 removed");
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

