public:
    void addItem(int urgency, const string& item) {
        if (items.size() >= MAX_ITEMS) {
            throw runtime_error("Cannot add item: inventory is full.");
        }
        items.push({urgency, item});
    }

    void removeItem(int urgency) {
        if (items.empty()) {
            throw runtime_error("Inventory is empty.");
        }
        auto it = items.find({urgency, ""});
        if (it == items.end()) {
            throw runtime_error("Item not found.");
        }
        items.erase(it);
    }

    string retrieveItem(int urgency) {
        if (items.empty()) {
            throw runtime_error("Inventory is empty.");
        }
        auto it = items.find({urgency, ""});
        if (it == items.end()) {
            throw runtime_error("Item not found.");
        }
        string item = it->second;
        items.erase(it);
        return item;
    }

    bool isInventoryFull() {
        return items.size() == MAX_ITEMS;
    }
};

