    fn new(max_entries: usize) -> Self {
        MediaCollection {
            entries: Vec::new(),
            max_entries,
        }
    }

    fn add_media(&mut self, title: &str, type_: MediaType) -> Result<(), String> {
        if self.entries.len() >= self.max_entries {
            return Err("Collection is full".to_string());
        }

        let id = self.entries.len() as u32 + 1;
        let entry = MediaEntry {
            id,
            title: title.to_string(),
            type,
        };
        self.entries.push(entry);
        Ok(())
    }

    fn find_media(&self, id: u32) -> Option<&MediaEntry> {
        self.entries.iter().find(|entry| entry.id == id)
    }

    fn update_media(&mut self, id: u32, title: &str) -> Result<(), String> {
        if let Some(entry) = self.find_media(id) {
            entry.title = title.to_string();
            Ok(())
        } else {
            Err("Media not found".to_string())
        }
    }

    fn delete_media(&mut self, id: u32) -> Result<(), String> {
        if let Some(entry) = self.find_media(id) {
            self.entries.remove(entry.id as usize);
            Ok(())
        } else {
            Err("Media not found".to_string())
        }
    }
}

