            return Err("Cannot add task: queue is full".to_string());
        }
        small_vec.push(Task { priority, data: data.to_string() });
        Ok(())
    }

    // Function to update a task
    fn update_task(index: usize, new_priority: i32, new_data: &str) -> Result<(), String> {
        if index >= small_vec.len() {
            return Err("Invalid index".to_string());
        }
        small_vec[index].priority = new_priority;
        small_vec[index].data = new_data.to_string();
        Ok(())
    }

    // Function to remove a task
    fn remove_task(index: usize) -> Result<(), String> {
        if index >= small_vec.len() {
            return Err("Invalid index".to_string());
        }
        small_vec.remove(index);
        Ok(())
    }

    // Example usage
