	counts := make(map[string]int)
	var wg sync.WaitGroup
	var mu sync.Mutex

	// Define the number of concurrent readers
	numReaders := 4

	// Open the log files
	files := []string{"log1.txt", "log2.txt", "log3.txt"}
	var fileHandles []os.File

	for _, file := range files {
		f, err := os.Open(file)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Error opening file %s: %v\n", file, err)
			continue
		}
		fileHandles = append(fileHandles, f)
	}

	// Read log entries concurrently
	for i := 0; i < numReaders; i++ {
		go func() {
			defer wg.Done()
			reader := bufio.NewReader(os.Stdin)
			for {
				line, err := reader.ReadString('\n')
				if err != nil {
					break
				}
				line = strings.TrimSpace(line)
				if line == "" {
					continue
				}
				// Process log entry
				mu.Lock()
				counts[line]++
				mu.Unlock()
			}
		}()
	}

	// Wait for all readers to complete
	wg.Wait()

	// Print the counts
	fmt.Println("Log entry counts:")
	for key, value := range counts {
		fmt.Printf("%s: %d\n", key, value)
	}
}

import queue

def shortest_path_distance(graph, num_nodes):
    # Initialize distance matrix
    dist = [[float('inf')] * num_nodes for _ in range(num_nodes)]
    for i in range(num_nodes):
        dist[i][i] = 0

    # Initialize queue for BFS
    q = queue.Queue()

    # Initialize queue with all pairs (i, j) where i < j
    for i in range(num_nodes):
        for j in range(i + 1, num_nodes):
            q.put((i, j))

    # Process queue
    while not q.empty():
        u, v = q.get()
        if dist[u][v] > graph[u][v]:
            dist[u][v] = graph[u][v]
            q.put((u, v))

    return dist

