int longestConsecutiveSequence(const std::vector<int>& nums) {
    std::map<int, bool> seen;
    int maxLen = 0;

    for (int num : nums) {
        if (seen.find(num) == seen.end()) {
            seen[num] = true;
            int currentLen = 1;
            // Check left and right
            if (seen.find(num - 1) != seen.end()) {
                currentLen += longestConsecutiveSequence(nums);
            }
            if (seen.find(num + 1) != seen.end()) {
                currentLen += longestConsecutiveSequence(nums);
            }
            maxLen = std::max(maxLen, currentLen);
        }
    }

    return maxLen;
}

int main() {
    std::vector<int> nums = {100, 4, 200, 1, 3, 2};
    std::cout << longestConsecutiveSequence(nums) << std::endl; // Output: 4
    return 0;
}

