bool hasLoop(Node* head) {
    unordered_set<Node*> visited;
    Node* current = head;
    while (current) {
        if (visited.find(current) != visited.end()) {
            return true;
        }
        visited.insert(current);
        current = current->next;
    }
    return false;
}

