class KthSmallestStream:
    def __init__(self, k):
        self.k = k
        self.heap = []

    def insert(self, num):
        if len(self.heap) < self.k:
            heapq.heappush(self.heap, num)
        else:
            if num < self.heap[0]:
                heapq.heappop(self.heap)
                heapq.heappush(self.heap, num)

    def get_kth_smallest(self):
        return self.heap[0]

