#include <iterator>

using namespace std;

vector<vector<int>> permuteUnique(vector<int> &nums) {
    vector<vector<int>> result;
    vector<int> current;

    sort(nums.begin(), nums.end());

    // Use backtracking to generate permutations
    backtrack(nums, current, result);

    return result;
}

void backtrack(vector<int> &nums, vector<int> &current, vector<vector<int>> &result) {
    if (current.size() == nums.size()) {
        result.push_back(current);
        return;
    }

    for (size_t i = 0; i < nums.size(); ++i) {
        // Skip duplicates
        if (i > 0 && nums[i] == nums[i-1]) continue;

        // Skip if current element is already in current
        if (current.size() > 0 && current[current.size() - 1] == nums[i]) continue;

        current.push_back(nums[i]);
        backtrack(nums, current, result);
        current.pop_back();
    }
}

int main() {
    vector<int> nums = {1, 1, 2, 3};
    vector<vector<int>> perms = permuteUnique(nums);

    for (const auto &perm : perms) {
        for (int num : perm) {
            cout << num << " ";
        }
        cout << endl;
    }

    return 0;
}
